/* Evidence: cmem-worked-cmem-strings-bytes-encoding-4 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 7458; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_strings_bytes_encoding_4(char *destination, size_t capacity, const char *source, size_t length) {
  if (destination == NULL || source == NULL || capacity == 0 || length >= capacity) return 0;
  memcpy(destination, source, length);
  destination[length] = '\0';
  return 1;
}

int main(void) {
  char text[8];
  int rejected = worked_cmem_strings_bytes_encoding_4(text, sizeof text, "changed-case", 12);
  int accepted = worked_cmem_strings_bytes_encoding_4(text, sizeof text, "memory", 6);
  int invariant = !rejected && accepted && strlen(text) == 6 && text[6] == '\0';
  printf("string length=%lu case=6 invariant=%d\n", (unsigned long)strlen(text), invariant);
  return invariant ? 0 : 1;
}

